In C++, you can start a new process and connect one file descriptor to its input and output using the `fork()` and `exec()` family of functions. Here's a basic example using pipes to connect the file descriptors:

```cpp
#include <unistd.h>
#include <iostream>
#include <sys/wait.h>

int main() {
    int pipefd[2];
    pid_t pid;

    // Create a pipe
    if (pipe(pipefd) == -1) {
        std::cerr << "Pipe failed" << std::endl;
        return 1;
    }

    // Fork a new process
    pid = fork();

    if (pid == -1) {
        std::cerr << "Fork failed" << std::endl;
        return 1;
    }

    if (pid == 0) { // Child process
        // Close unused ends of the pipe
        close(pipefd[1]); // Close write end in child

        // Redirect stdin and stdout to the pipe
        dup2(pipefd[0], STDIN_FILENO); // Input from pipe
        dup2(pipefd[0], STDOUT_FILENO); // Output to pipe

        // Close the pipe now that it's been duplicated
        close(pipefd[0]);

        // Execute a command
        execlp("cat", "cat", NULL);
        std::cerr << "Exec failed" << std::endl;
        _exit(1);
    } else { // Parent process
        // Close unused ends of the pipe
        close(pipefd[0]); // Close read end in parent

        // Write to the pipe
        std::cout << "Hello, child!" << std::endl;

        // Close the write end now that we're done writing
        close(pipefd[1]);

        // Wait for the child process to finish
        wait(NULL);
    }

    return 0;
}
```

This example creates a pipe, forks a new process, and redirects the child's standard input and output to the pipe. The parent process writes to the pipe and the child reads from it. Note that `execlp` is used to execute a command in the child process.
